steps.script:
// The original selector contained literal newlines (\n) which made it an invalid CSS selector.
// We remove the newlines and use a simplified, robust selector based on the actual DOM structure.
const deepThinkSelector = '.model-select-wrapper .ci-model-button';

// Check if the deep thinking button exists
const exists = await $exists(deepThinkSelector, 5000);

if (exists) {
  // Read current text to check state
  const currentText = await $extract(deepThinkSelector, 'textContent', 5000);

  // Click to toggle deep thinking mode on
  await $click(deepThinkSelector);

  // Wait a moment for the toggle to take effect
  await new Promise(r => setTimeout(r, 1500));

  // Verify the toggle happened - check if text changed or button state changed
  const newText = await $extract(deepThinkSelector, 'textContent', 5000);

  return {
    deepThinkingEnabled: true,
    previousText: currentText,
    currentText: newText,
    toggled: currentText !== newText
  };
} else {
  // The button might not be visible yet or might have a different structure
  // Try alternative: look for the model-select-wrapper area
  const modelButtonExists = await $exists('.model-select-wrapper .ci-model-button', 3000);

  if (modelButtonExists) {
    // Click the model button to open the dropdown, then look for deep thinking option
    await $click('.model-select-wrapper .ci-model-button');
    await new Promise(r => setTimeout(r, 1000));

    // Check if deep thinking option appeared
    const deepOptionExists = await $exists('.deep-search-text', 3000);
    if (deepOptionExists) {
      await $click('.deep-search-text');
      await new Promise(r => setTimeout(r, 1500));
      return { deepThinkingEnabled: true, method: 'dropdown' };
    }
  }

  return {
    deepThinkingEnabled: false,
    error: 'Deep thinking button not found'
  };
}

// Type the question into the textarea
await $type('#chat-textarea', __input__.question);

// Brief pause to ensure input is registered
await new Promise(r => setTimeout(r, 500));

// Click the submit button
await $click('#ci-submit-button-ai');

// Wait a moment for the question to be submitted and page to start transitioning
await new Promise(r => setTimeout(r, 2000));

// Verify submission happened - check if the textarea is cleared or chat response area appeared
const textareaValue = await $extract('#chat-textarea', 'value', 3000);

// If textarea still has the question text, submission may not have worked
if (textareaValue && textareaValue.trim() === __input__.question.trim()) {
  // Retry: click submit again
  await $click('#ci-submit-button-ai');
  await new Promise(r => setTimeout(r, 2000));
}

return {
  submitted: true,
  question: __input__.question
};

// Wait a bit for generation to start
await new Promise(r => setTimeout(r, 3000));

// Check if the answer container has finished generating
// The container changes from data-status="GENERATING" to data-status="COMPLETE"
const isComplete = await $exists('.cs-answer-container[data-status="COMPLETE"]', 3000);

if (isComplete) {
  // Verify content stability to ensure streaming is fully done
  const stable = await $waitForStable('.cs-answer-container[data-status="COMPLETE"] .cosd-markdown-content', {
    interval: 1500,
    stableChecks: 2,
    maxMs: 20000
  });

  if (stable) {
    return { done: true };
  }
}

return { done: false };

// 1. Extract Thinking Process
const thinkingSelector = 'div.ai-entry-block.ai-thinking-steps > div._thinking-steps_1eyeq_1 > div._collapse-container_er9xf_1 > main._expand_er9xf_20';
let thinking = '';
try {
  thinking = await $extract(thinkingSelector, null, 5000);
} catch(e) {
  thinking = '';
}

// 2. Extract Answer
// The previous selector `div.ai-entry-block.ai-markdown div.cosd-markdown-content` was too broad and included the thinking process DOM.
// We exclude the `.ai-thinking-steps` block to ensure we only get the actual answer.
const answerSelector = 'div.ai-entry-block.ai-markdown:not(.ai-thinking-steps) div.cosd-markdown-content';
const answerMarkdownBlocks = await $list(answerSelector);
let answer = '';
if (answerMarkdownBlocks && answerMarkdownBlocks.length > 0) {
  answer = answerMarkdownBlocks.map(el => el.textContent).join('\n\n');
}

// 3. Validate extraction (Rule 4: Must not return empty as success)
if (!thinking || thinking.trim().length < 10) {
  return { done: false };
}
if (!answer || answer.trim().length < 10) {
  return { done: false };
}

// 4. Return conforming to output schema
return {
  question: __input__.question,
  thinking: thinking.trim(),
  answer: answer.trim()
};
